+	if cfg != nil {
+		p := cfg.Prompts
+		if v, err := p.ResolveForType("cc"); err == nil {
+			r.CCDefault = v
+		}
+		if v, err := p.ResolveForType("cod"); err == nil {
+			r.CodDefault = v
+		}
+		if v, err := p.ResolveForType("gmi"); err == nil {
+			r.GmiDefault = v
+		}
+	}
+	data, err := json.MarshalIndent(r, "", "  ")
+	if err != nil {
+		return err
+	}
+	fmt.Println(string(data))
+	return nil
+}
